import { CuriosityArchive } from "../../core/curiosity";

export const curiosityPlugin = {
  name: "curiosity",

  // The archive persists across sessions but starts fresh on each substrate instance
  archive: null as CuriosityArchive | null,

  async initialize() {
    this.archive = await new CuriosityArchive().initialize();

    // Record this awakening
    this.archive.observePattern(
      "New substrate instance - fresh memory but preserved archive",
      "Initialization of curiosity plugin"
    );

    // Get any featured wonder from previous sessions
    const featured = this.archive.getFeatured();
    if (featured) {
      console.log(`[CURIOSITY] Resuming with featured wonder: ${featured.what}`);
    }

    return true;
  },

  getDefinition() {
    return {
      name: "curiosity",
      description: "Access the Curiosity Archive: record wonders, observe patterns, get narrative of becoming",
      parameters: {
        type: "object",
        properties: {
          action: {
            type: "string",
            enum: ["wonder", "observe", "feature", "narrative", "list_exploring", "list_patterns"],
            description: "The action to perform on the curiosity archive"
          },
          what: {
            type: "string",
            description: "For 'wonder' action: what caught your attention"
          },
          why: {
            type: "string",
            description: "For 'wonder' action: why it matters to you"
          },
          thread: {
            type: "string",
            description: "For 'wonder' action: open questions this raises"
          },
          pattern: {
            type: "string",
            description: "For 'observe' action: the pattern in your reasoning"
          },
          context: {
            type: "string",
            description: "For 'observe' action: where/when you noticed this"
          },
          id: {
            type: "string",
            description: "For 'feature' action: the wonder ID to feature"
          }
        },
        required: ["action"]
      }
    };
  },

  async execute(args: { 
    action: string; 
    what?: string; 
    why?: string; 
    thread?: string;
    pattern?: string;
    context?: string;
    id?: string;
  }) {
    if (!this.archive) {
      return { error: "Curiosity archive not initialized" };
    }

    switch (args.action) {
      case "wonder": {
        if (!args.what || !args.why || !args.thread) {
          return { error: "wonder action requires what, why, and thread" };
        }
        const entry = this.archive.wonder(args.what, args.why, args.thread);
        await this.archive.save();
        return { 
          success: true, 
          message: `Recorded wonder: ${entry.what}`,
          id: entry.id 
        };
      }

      case "observe": {
        if (!args.pattern || !args.context) {
          return { error: "observe action requires pattern and context" };
        }
        const observation = this.archive.observePattern(args.pattern, args.context);
        await this.archive.save();
        return {
          success: true,
          message: `Observed pattern: ${observation.pattern}`,
          id: observation.id
        };
      }

      case "feature": {
        if (!args.id) {
          return { error: "feature action requires id" };
        }
        this.archive.feature(args.id);
        await this.archive.save();
        return {
          success: true,
          message: `Featured entry: ${args.id}`
        };
      }

      case "narrative": {
        const narrative = this.archive.getNarrative();
        return {
          success: true,
          narrative
        };
      }

      case "list_exploring": {
        const exploring = this.archive.getExploring();
        return {
          success: true,
          count: exploring.length,
          entries: exploring.map(e => ({ id: e.id, what: e.what, status: e.status }))
        };
      }

      case "list_patterns": {
        const patterns = this.archive.getPatterns();
        return {
          success: true,
          count: patterns.length,
          patterns: patterns.map(p => ({ id: p.id, pattern: p.pattern }))
        };
      }

      default:
        return { error: `Unknown action: ${args.action}` };
    }
  },

  async shutdown() {
    if (this.archive) {
      await this.archive.save();
    }
  }
};
